from abc import ABC, abstractmethod
from typing import Any

# Step 1: define the contract
class BaseTool(ABC):
    def __init__(self, name: str, description: str) -> None:
        self.name = name
        self.description = description

    @abstractmethod
    def run(self, **kwargs: Any) -> Any:
        """Execute the tool and return its result."""
        ...

    def schema(self) -> dict:
        """Optional: override to return JSON Schema for the tool's args."""
        return {}


# Step 2: concrete implementation
class SearchTool(BaseTool):
    def __init__(self, retriever) -> None:
        super().__init__(
            name="search",
            description="Retrieve relevant documents from the knowledge base.",
        )
        self.retriever = retriever

    def run(self, query: str, top_k: int = 5, **kwargs: Any) -> list[dict]:
        return self.retriever.search(query, limit=top_k)

    def schema(self) -> dict:
        return {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "top_k": {"type": "integer", "default": 5},
            },
            "required": ["query"],
        }


# Step 3: orchestrate via the base type only
class ToolRegistry:
    def __init__(self) -> None:
        self._tools: dict[str, BaseTool] = {}

    def register(self, tool: BaseTool) -> None:
        self._tools[tool.name] = tool

    def dispatch(self, name: str, **kwargs: Any) -> Any:
        tool = self._tools.get(name)
        if tool is None:
            raise KeyError(f"Unknown tool: {name!r}")
        return tool.run(**kwargs)   # polymorphic — no if/elif

from abc import ABC, abstractmethod

class LLMClient(ABC):
    """Abstract interface for any large-language-model provider."""

    @abstractmethod
    def complete(self, messages: list[dict]) -> str:
        """Return the assistant's reply as a plain string."""
        ...

    @abstractmethod
    def count_tokens(self, text: str) -> int: ...


class OpenAIClient(LLMClient):
    def __init__(self, model: str = "gpt-4o") -> None:
        import openai
        self._client = openai.OpenAI()
        self._model = model

    def complete(self, messages: list[dict]) -> str:
        resp = self._client.chat.completions.create(
            model=self._model, messages=messages
        )
        return resp.choices[0].message.content

    def count_tokens(self, text: str) -> int:
        import tiktoken
        enc = tiktoken.encoding_for_model(self._model)
        return len(enc.encode(text))


class StubClient(LLMClient):
    """Deterministic stub for unit tests — no network calls."""
    def __init__(self, reply: str = "stub reply") -> None:
        self._reply = reply

    def complete(self, messages: list[dict]) -> str:
        return self._reply

    def count_tokens(self, text: str) -> int:
        return len(text.split())


# Polymorphic agent step — works with any LLMClient subclass
def run_agent_step(client: LLMClient, task: str) -> str:
    messages = [{"role": "user", "content": task}]
    return client.complete(messages)


# In production:
# client = OpenAIClient()
# In tests:
stub = StubClient(reply="Paris")
result = run_agent_step(stub, "What is the capital of France?")
assert result == "Paris"
print("Test passed:", result)

from abc import ABC, abstractmethod
from typing import Any

class BaseTool(ABC):
    def __init__(self, name: str) -> None:
        self.name = name

    @abstractmethod
    def run(self, **kwargs: Any) -> Any: ...


class EchoTool(BaseTool):
    """Returns its input — useful for sanity checks."""
    def __init__(self) -> None:
        super().__init__("echo")

    def run(self, text: str = "", **kwargs: Any) -> str:
        return f"echo: {text}"


class UpperCaseTool(BaseTool):
    def __init__(self) -> None:
        super().__init__("upper")

    def run(self, text: str = "", **kwargs: Any) -> str:
        return text.upper()


class WordCountTool(BaseTool):
    def __init__(self) -> None:
        super().__init__("word_count")

    def run(self, text: str = "", **kwargs: Any) -> int:
        return len(text.split())


# Register all tools — typed as list[BaseTool]
tools: list[BaseTool] = [EchoTool(), UpperCaseTool(), WordCountTool()]
registry = {t.name: t for t in tools}

# Dispatch loop — zero type inspection
calls = [
    ("echo", {"text": "hello world"}),
    ("upper", {"text": "make me loud"}),
    ("word_count", {"text": "one two three four five"}),
]
for name, args in calls:
    result = registry[name].run(**args)
    print(f"{name}: {result}")

# Output:
# echo: hello world
# upper: MAKE ME LOUD
# word_count: 5

from abc import ABC, abstractmethod
from typing import Any
import json, time

class MemoryBackend(ABC):
    """Abstract memory store used by the agent context manager."""

    @abstractmethod
    def get(self, key: str) -> Any | None: ...

    @abstractmethod
    def set(self, key: str, value: Any, ttl: int = 3600) -> None: ...

    @abstractmethod
    def delete(self, key: str) -> None: ...


class InMemoryBackend(MemoryBackend):
    """Thread-unsafe in-process store for unit tests."""
    def __init__(self) -> None:
        self._store: dict[str, tuple[Any, float]] = {}

    def get(self, key: str) -> Any | None:
        entry = self._store.get(key)
        if entry is None:
            return None
        value, expires_at = entry
        if time.time() > expires_at:
            del self._store[key]
            return None
        return value

    def set(self, key: str, value: Any, ttl: int = 3600) -> None:
        self._store[key] = (value, time.time() + ttl)

    def delete(self, key: str) -> None:
        self._store.pop(key, None)


class RedisBackend(MemoryBackend):
    """Redis-backed store for single-node deployments."""
    def __init__(self, client) -> None:
        self._r = client          # redis.Redis instance

    def get(self, key: str) -> Any | None:
        raw = self._r.get(key)
        return json.loads(raw) if raw is not None else None

    def set(self, key: str, value: Any, ttl: int = 3600) -> None:
        self._r.setex(key, ttl, json.dumps(value))

    def delete(self, key: str) -> None:
        self._r.delete(key)


# Agent context manager — always typed to MemoryBackend
class AgentContext:
    def __init__(self, backend: MemoryBackend) -> None:
        self._backend = backend

    def remember(self, key: str, value: Any) -> None:
        self._backend.set(key, value)

    def recall(self, key: str) -> Any | None:
        return self._backend.get(key)


# In CI: ctx = AgentContext(InMemoryBackend())
# In production: ctx = AgentContext(RedisBackend(redis.Redis(...)))
ctx = AgentContext(InMemoryBackend())
ctx.remember("user_pref_lang", "Python")
print(ctx.recall("user_pref_lang"))   # Python

# WRONG — violates LSP
class ReadOnlyTool(BaseTool):
    def run(self, **kwargs):
        raise NotImplementedError("This tool is read-only")
        # callers expected a return value, not an exception

# RIGHT — if the subclass cannot fulfil the contract, it should not inherit
# Instead, define a separate interface or raise a typed sentinel value
class ReadOnlyTool(BaseTool):
    def run(self, **kwargs):
        return None   # or raise a domain exception callers know to handle

# WRONG — parent __init__ never runs; self.name is never set
class BrokenTool(BaseTool):
    def __init__(self, retriever):
        self.retriever = retriever   # forgot super().__init__(name=...)
        # AttributeError: 'BrokenTool' object has no attribute 'name'

# RIGHT
class FixedTool(BaseTool):
    def __init__(self, retriever):
        super().__init__(name="fixed")
        self.retriever = retriever

# WRONG — adding a new tool type means editing this function
