# RIGHT — move describe() into each class
class BaseTool(ABC):
    @abstractmethod
    def describe(self) -> str: ...

class SearchTool(BaseTool):
    def describe(self) -> str:
        return f"Search with {self.retriever}"

# Caller is one line, regardless of how many tool types exist:
