from abc import ABC, abstractmethod

class OutputParser(ABC):
    @abstractmethod
    def parse(self, raw: str) -> dict: ...

    @property
    @abstractmethod
    def schema(self) -> dict: ...

# Attempting to instantiate without implementing both raises TypeError immediately
# parser = OutputParser()   # TypeError: Can't instantiate abstract class OutputParser

from typing import Protocol, runtime_checkable

@runtime_checkable
class Runnable(Protocol):
    name: str
    def run(self, **kwargs) -> object: ...

# Any class with .name and .run satisfies Runnable without inheriting from it
class ThirdPartyTool:
    name = "third_party"
    def run(self, **kwargs): return "ok"

assert isinstance(ThirdPartyTool(), Runnable)  # True at runtime

from dataclasses import dataclass, field
from abc import ABC, abstractmethod

@dataclass
class BaseConfig(ABC):
    model: str
    temperature: float = 0.7

    @abstractmethod
    def provider(self) -> str: ...

@dataclass
class OpenAIConfig(BaseConfig):
    api_key: str = field(default="", repr=False)

    def provider(self) -> str:
        return "openai"

cfg = OpenAIConfig(model="gpt-4o", api_key="sk-...")
print(cfg.provider(), cfg.model)

from dataclasses import dataclass
from abc import ABC, abstractmethod
from typing import Any

@dataclass
class ToolResult:
    value: Any = None
    error: str | None = None

    @property
    def ok(self) -> bool:
        return self.error is None

class SafeBaseTool(ABC):
    @abstractmethod
    def _execute(self, **kwargs: Any) -> Any: ...

    def run(self, **kwargs: Any) -> ToolResult:
        """Template method — handles errors so callers never see raw exceptions."""
        try:
            return ToolResult(value=self._execute(**kwargs))
        except Exception as exc:
            return ToolResult(error=str(exc))
